class CombatAI{constructor(e){this.game=e}_init_planTurn(){window.entities&&window.entities.forEach(e=>{"enemy"===e.type&&this.planTurn(e)})}planTurn(i){if(i&&"enemy"===i.type&&!(i.hp<=0)){var e=window.entities?window.entities.find(e=>"player"===e.type):null;if(e){e=this.game.grid.getHexNeighbors(e.plannedQ,e.plannedR);let r=new Set(this.game.grid.nonspawn.map(e=>Number(e.q)+","+Number(e.r))),a=null,o=1/0;if(e.forEach(n=>{var e,t=Number(n.q)+","+Number(n.r);r.has(t)||this.game.grid.hexes.some(e=>Number(e.q)===Number(n.q)&&Number(e.r)===Number(n.r))&&(t=n.q-i.plannedQ,e=n.r-i.plannedR,(t=Math.sqrt(t*t+e*e))<o)&&(o=t,a=n)}),a){var t=this.game.grid.findSmartPath(i,a.q,a.r);if(0===t.length)console.log("[CombatAI]: Путь до соседней клетки игрока заблокирован стенками.");else{let n=0;for(let e=0;e<t.length;e++){var l=t[e],s=i.plannedStepsCount+1,d=i.getStepCostAP(s);if(!(i.currentAP>=d)){console.log(`[CombatAI]: Врагу не хватило AP на ${s}-й шаг (нужно ${d} AP). Он пройдет только ${n} шагов.`);break}i.actionQueue.addMoveAction(l.q,l.r,"idle",d),i.plannedStepsCount++,n++,i.plannedQ=l.q,i.plannedR=l.r}i.updatePlannedScreenCoordinates&&i.updatePlannedScreenCoordinates(),console.log(`[CombatAI]: Планирование завершено. Враг сделает шагов: ${n}. Остаток AP: `+i.currentAP)}}else console.log("[CombatAI]: Все клетки вокруг игрока заняты. Враг стоит на месте.")}}}}export{CombatAI};